class Solution:
    def findTheDifference(self, s: str, t: str) -> str:
        
        # Initialize a variable to store the result
        result = 0
        
        # XOR all characters in string s
        for char in s:
            result ^= ord(char)
        
        # XOR all characters in string t
        for char in t:
            result ^= ord(char)
        
        # The result now holds the ASCII value of the extra character in t
        return chr(result)
    


s = ""
t = ""

sol = Solution()
result = sol.findTheDifference(s, t)
print(result)

